export default function LocaleSwitcher() {
  const t = useTranslations('LocaleSwitcher');
  const locale = useLocale();
  const otherLocale = locale === 'en' ? 'de' : 'en';

  return (
    <Link href={'/' + otherLocale} prefetch={false}>
      {t('switchLocale', {locale: otherLocale})}
    </Link>
  );
}

export default function ZodForm({action, children}: Props) {
  const [state, formAction] = useActionState(action, null);
  const hasErrors = state && !state.success;

  return (
    <form action={formAction}>
      {children}
      {hasErrors && <p>{state.errors.fieldErrors?.task?.join(', ')}</p>}
    </form>
  );
}

export default function ZodFormExample() {
  const t = useTranslations('ZodFormExample');

  return (
    <section>
      <h2>Zod form</h2>
      <ZodForm action={submitAction}>
        <input name="task" placeholder={t('task')} type="text" />
